bomData.valueScript:
//====================================================================
  // Input the BomId's and quantity of baskets
  //====================================================================

  const bomRawData = JSON.parse(partSelf.pa_HardwareId);
  const frameId = bomRawData.FrameId;
  const basketId = bomRawData.BasketId;
  const basketQty = bomRawData.BasketsQty;

  //====================================================================
  // Get data for bomElements
  //====================================================================

  // Variables
  const frameParts = GlobalFunc.find_HardwareLibraryMapping(frameId);
  const basketPart = GlobalFunc.find_HardwareLibraryMapping(basketId);

  let bomElements: { data: ICT_tab_HardwareLibraryMapping, source: 'frame' | 'basket' }[] = [];

  // Merge the bom elements
  frameParts.forEach(elem => {
      bomElements.push({ data: elem, source: 'frame' });
  });

  basketPart.forEach(elem => {
      bomElements.push({ data: elem, source: 'basket' });
  });

  //====================================================================
  // Insert the hardware items
  //====================================================================

  bomElements.forEach(x => 
  {  
    let HardwareElem = this.addbomout_Hardware();
    let HardwareInfo = GlobalFunc.find_HardwareLibrary(x.data.SupplierArticleNumber!,x.data.Supplier!);

    HardwareElem.bom_Supplier = HardwareInfo.in_Supplier;
    HardwareElem.bom_SupplierArticle = HardwareInfo.in_SupplierArticleNumber;
    HardwareElem.bom_Description1 = HardwareInfo.Description;
    HardwareElem.bom_Description2 = HardwareInfo.Description2;
    HardwareElem.bom_Color = HardwareInfo.Color;
    HardwareElem.bom_ElementCategory = HardwareInfo.Category;
    HardwareElem.bom_Length = HardwareInfo.Length;
    HardwareElem.bom_Width = HardwareInfo.Width;
    HardwareElem.bom_Thk = HardwareInfo.Thickness;
    HardwareElem.bom_Qty = x.source === 'basket' ? basketQty : 1;
  })
